type Cell = [number, number];

const cellKey = (x: number, y: number): string => `${x},${y}`;

const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number => {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (liveSet.has(cellKey(x + dx, y + dy))) count++;
    }
  }
  return count;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));

  const candidateMap = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const cx = x + dx;
        const cy = y + dy;
        candidateMap.set(cellKey(cx, cy), [cx, cy]);
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, [x, y]] of candidateMap) {
    const neighbors = countLiveNeighbors(x, y, liveSet);
    const isAlive = liveSet.has(key);
    if (isAlive && (neighbors === 2 || neighbors === 3)) {
      result.push([x, y]);
    } else if (!isAlive && neighbors === 3) {
      result.push([x, y]);
    }
  }
  return result;
}

